<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Sorting Visualizer</title>
  <style>
    body {
      background-color: #1e1e1e;
      color: white;
      font-family: sans-serif;
    }
    #bars {
      display: flex;
      margin: 20px auto;
      width: 90%;
      max-width: 800px;
      height: 300px;
      overflow: hidden;
    }
    .bar {
      flex: 1;
      margin: 0 2px;
      background-color: #4CAF50;
      transition: all 0.3s ease-out;
    }
    button {
      padding: 10px 20px;
      margin: 10px;
      font-size: 16px;
      cursor: pointer;
    }
    #sort, #shuffle, #reset {
      background-color: #4CAF50;
      color: white;
      border: none;
      border-radius: 4px;
    }
    #sort:hover, #shuffle:hover, #reset:hover {
      background-color: #45a049;
    }
  </style>
</head>
<body>
  <div id="bars"></div>
  <div>
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>

  <script>
    (function() {
      const N = 20;
      let originalArray = Array.from({length: N}, (_, i) => i + 1);
      let arr = [...originalArray];
      let pass = 0;
      let currentIndex = 0;
      let swappedThisPass = false;
      let isFinished = false;

      function resetState() {
        pass = 0;
        currentIndex = 0;
        swappedThisPass = false;
        isFinished = false;
      }

      window.viz = {
        array: () => [...arr],
        setArray(newArr) {
          arr = newArr.slice();
          resetState();
          redrawBars();
        },
        sortStep() {
          if (isFinished || this.sorted()) {
            return true;
          }

          const maxIndexForPass = arr.length - pass - 1;

          if (currentIndex < maxIndexForPass) {
            if (arr[currentIndex] > arr[currentIndex + 1]) {
              [arr[currentIndex], arr[currentIndex + 1]] = [
                arr[currentIndex + 1],
                arr[currentIndex]
              ];
              swappedThisPass = true;
              redrawBars();
            }
            currentIndex++;
            return false;
          } else {
            if (!swappedThisPass) {
              isFinished = true;
              return true;
            } else {
              pass++;
              currentIndex = 0;
              swappedThisPass = false;
              return false;
            }
          }
        },
        sorted() {
          for (let i = 0; i < arr.length - 1; i++) {
            if (arr[i] > arr[i + 1]) return false;
          }
          return true;
        }
      };

      function redrawBars() {
        const container = document.getElementById('bars');
        const maxVal = Math.max(...arr);
        container.innerHTML = '';
        arr.forEach(value => {
          const bar = document.createElement('div');
          bar.className = 'bar';
          const height = (value / maxVal) * 200; // Max height of 200px
          bar.style.height = height + 'px';
          container.appendChild(bar);
        });
      }

      redrawBars();

      document.getElementById('shuffle').addEventListener('click', () => {
        const shuffled = [...originalArray].sort(() => Math.random() - 0.5);
        window.viz.setArray(shuffled);
      });

      document.getElementById('reset').addEventListener('click', () => {
        window.viz.setArray([...originalArray]);
      });

      document.getElementById('sort').addEventListener('click', () => {
        function animateStep() {
          if (!window.viz.sortStep()) {
            setTimeout(animateStep, 50);
          }
        }
        animateStep();
      });
    })();
  </script>
</body>
</html>
